class Solution:
    def strangePrinter(self, s: str) -> int:
        n = len(s)
        s = ''.join([a for i, a in enumerate(s) if i == 0 or a != s[i-1]])
        n = len(s)
        memo = {}

        def dp(i, j):
            if (i, j) in memo:
                return memo[(i, j)]
            if i > j:
                return 0
            if i == j:
                return 1
            res = dp(i + 1, j) + 1
            for k in range(i + 1, j + 1):
                if s[k] == s[i]:
                    res = min(res, dp(i, k - 1) + dp(k, j))
            memo[(i, j)] = res
            return res

        return dp(0, n - 1)
